1	/**
2	 * `chat` stage. Renders the welcome conversation stream followed by the holo
3	 * card reveal. The composer is always a "Continue to GAIA" CTA — the onboarding
4	 * first message intentionally closes its own loop, so there is no free-chat
5	 * input here. Active once the backend has produced `first_message_conversation_id`.
6	 */
7	
8	"use client";
9	
10	import * as m from "motion/react-m";
11	import type { Dispatch } from "react";
12	import { useEffect } from "react";
13	import ChatBubbleBot from "@/features/chat/components/bubbles/bot/ChatBubbleBot";
14	import ChatBubbleUser from "@/features/chat/components/bubbles/user/ChatBubbleUser";
15	import { LoadingIndicator } from "@/features/chat/components/interface/LoadingIndicator";
16	import {
17	  BOT_BUBBLE_DEFAULTS,
18	  USER_BUBBLE_DEFAULTS,
19	} from "../../constants/bubbleDefaults";
20	import {
21	  MOTION_COMPOSER_CTA,
22	  MOTION_FADE_UP_LARGE,
23	  MOTION_STREAM_MESSAGE,
24	} from "../../constants/motion";
25	import {
26	  type UseOnboardingChatReturn,
27	  useOnboardingChat,
28	} from "../../hooks/useOnboardingChat";
29	import type { Action, OnboardingState } from "../../state/types";
30	import { OnboardingCTAButton } from "../OnboardingCTAButton";
31	import { HoloCardReveal } from "../reveal/HoloCardReveal";
32	
33	interface ChatProps {
34	  state: OnboardingState;
35	  dispatch: Dispatch<Action>;
36	  chat: UseOnboardingChatReturn;
37	}
38	
39	export interface OnboardingChatStages {
40	  /** Live welcome conversation — seeded by the backend, lands the user in
41	   *  `/c/{first_message_conversation_id}` after onboarding. Never receives
42	   *  the run-now demo. */
43	  welcome: UseOnboardingChatReturn;
44	  /** Throwaway conversation that runs the in-place run-now todo demo. Kept
45	   *  separate from `welcome` so the executed turn doesn't appear in the
46	   *  post-onboarding chat. */
47	  todoDemo: UseOnboardingChatReturn;
48	}
49	
50	/**
51	 * Page-level hook that wires up two independent chat streams: the welcome
52	 * conversation (for the final `chat` stage) and a throwaway conversation
53	 * for the run-now todo demo. Splitting them stops the run-now turn from
54	 * bleeding into the welcome conversation when the user clicks
55	 * "Continue to GAIA". Also clears `todoExecutionMessage` once the demo
56	 * conversation has consumed it so a remount can't re-queue.
57	 */
58	export function useChatStage(
59	  state: OnboardingState,
60	  dispatch: Dispatch<Action>,
61	): OnboardingChatStages {
62	  const welcomeConvoId = state.server?.first_message_conversation_id ?? null;
63	  const todoDemoConvoId = state.todoExecutionConvoId;
64	  const pendingTodoMessage = state.todoExecutionMessage;
65	
66	  const welcome = useOnboardingChat(welcomeConvoId, null);
67	  const todoDemo = useOnboardingChat(todoDemoConvoId, pendingTodoMessage);
68	
69	  useEffect(() => {
70	    if (!pendingTodoMessage || !todoDemoConvoId) return;
71	    dispatch({ type: "clearTodoExecutionMessage" });
72	  }, [pendingTodoMessage, todoDemoConvoId, dispatch]);
73	
74	  return { welcome, todoDemo };
75	}
76	
77	const RUN_NOW_PREFIX = "Execute this todo for me: ";
78	
79	/** Shared stream renderer — used by both the in-place todo demo inside
80	 *  `revealTodos` and by the final `chat` stage. When `hideRunNowUserMessage`
81	 *  is true, the auto-sent "Execute this todo for me: ..." user turn is
82	 *  filtered out entirely (the demo container shows a static "selected todo"
83	 *  indicator instead). */
84	export function OnboardingChatStream({
85	  chat,
86	  hideRunNowUserMessage = false,
87	  hideBotAvatar = false,
88	}: {
89	  chat: UseOnboardingChatReturn;
90	  hideRunNowUserMessage?: boolean;
91	  hideBotAvatar?: boolean;
92	}) {
93	  const visibleMessages = hideRunNowUserMessage
94	    ? chat.streamMessages.filter(
95	        (msg) =>
96	          !(
97	            msg.role === "user" &&
98	            typeof msg.content === "string" &&
99	            msg.content.startsWith(RUN_NOW_PREFIX)
100	          ),
101	      )
102	    : chat.streamMessages;
103	  return (
104	    <>
105	      {visibleMessages.map((msg) => (
106	        <m.div key={msg.id} {...MOTION_STREAM_MESSAGE}>
107	          {msg.role === "user" ? (
108	            <ChatBubbleUser
109	              {...USER_BUBBLE_DEFAULTS}
110	              text={msg.content}
111	              message_id={msg.id}
112	              date={msg.createdAt.toISOString()}
113	              fileData={msg.fileData}
114	            />
115	          ) : (
116	            <ChatBubbleBot
117	              {...BOT_BUBBLE_DEFAULTS}
118	              text={msg.content}
119	              message_id={msg.id}
120	              loading={msg.status === "sending"}
121	              tool_data={msg.tool_data ?? undefined}
122	              todo_progress={msg.todo_progress ?? undefined}
123	              memory_data={msg.memory_data ?? undefined}
124	              image_data={msg.image_data ?? undefined}
125	              date={msg.createdAt.toISOString()}
126	              hideAvatar={hideBotAvatar}
127	            />
128	          )}
129	        </m.div>
130	      ))}
131	
132	      {chat.isChatSending &&
133	        !visibleMessages.some(
134	          (msg) => msg.role === "assistant" && msg.content,
135	        ) && (
136	          <LoadingIndicator
137	            loadingText={
138	              hideRunNowUserMessage
139	                ? "Auto-executing todo…"
140	                : "GAIA is thinking…"
141	            }
142	            loadingTextKey={0}
143	            noPadding={hideRunNowUserMessage}
144	          />
145	        )}
146	    </>
147	  );
148	}
149	
150	export function Chat({ state }: Omit<ChatProps, "dispatch" | "chat">) {
151	  const showHolo = state.server?.has_personalization && state.server;
152	  if (!showHolo || !state.server) return null;
153	
154	  const firstMessage = state.server.first_message;
155	
156	  return (
157	    <m.div className="mt-4 space-y-4" {...MOTION_FADE_UP_LARGE}>
158	      {firstMessage && (
159	        <ChatBubbleBot
160	          {...BOT_BUBBLE_DEFAULTS}
161	          text={firstMessage}
162	          message_id="onboarding-first-message"
163	          loading={false}
164	          date={new Date().toISOString()}
165	        />
166	      )}
167	      <div className="my-4">
168	        <HoloCardReveal personalizationData={state.server} />
169	      </div>
170	    </m.div>
171	  );
172	}
173	
174	/** Composer for the `chat` stage. Always renders the "Continue to GAIA" CTA —
175	 *  the onboarding chat stage ends with a closed-loop message (no question), so
176	 *  the user's only forward move is into the full chat experience. The CTA
177	 *  lands the user inside the seeded welcome conversation when available so
178	 *  the post-onboarding welcome UI shows up immediately. */
179	export function ChatComposer({ state }: Omit<ChatProps, "dispatch" | "chat">) {
180	  const welcomeConvoId = state.server?.first_message_conversation_id;
181	  const href = welcomeConvoId ? `/c/${welcomeConvoId}` : "/c";
182	  return (
183	    <m.div className="flex justify-center pb-2" {...MOTION_COMPOSER_CTA}>
184	      <OnboardingCTAButton href={href}>Continue to GAIA</OnboardingCTAButton>
185	    </m.div>
186	  );
187	}
