  "workflows_creating",
  "todos_creating",
  "triage_analyzing",
];

export function getCurrentProgress(s: OnboardingState): string | null {
  for (const stage of POST_WRITING_PROGRESS_STAGES) {
    const value = s.progressByStage[stage];
    if (value) return value;
